import React, { useState, useEffect, useMemo } from 'react';
import axios from 'axios';

const App = () => {
  const [inputText, setInputText] = useState('');
  const [parsedFiles, setParsedFiles] = useState([]);
  const [loading, setLoading] = useState(false);

  // Smart Parser Function
  const parseText = (text) => {
    const extractedFiles = [];

    // Helper to safely add files
    const addFile = (path, content) => {
      const cleanPath = path.trim();
      if (!cleanPath) return;
      if (!extractedFiles.find((f) => f.path === cleanPath)) {
        extractedFiles.push({ path: cleanPath, content });
      }
    };

    // 1a. Python dict format: "path": """content"""
    const pythonTripleRegex = /"([^"]+)"\s*:\s*"""([\s\S]*?)"""/g;
    let match;
    while ((match = pythonTripleRegex.exec(text)) !== null) {
      addFile(match[1], match[2]);
    }

    // 1b. Python dict single quote format: 'path': '''content'''
    const pythonSingleTripleRegex = /'([^']+)'\s*:\s*'''([\s\S]*?)'''/g;
    while ((match = pythonSingleTripleRegex.exec(text)) !== null) {
      addFile(match[1], match[2]);
    }

    // 1c. Python dict empty strings: "path": ""
    const pythonEmptyRegex = /"([^"]+)"\s*:\s*""(?!")/g;
    while ((match = pythonEmptyRegex.exec(text)) !== null) {
      addFile(match[1], '');
    }

    // 2. Markdown format: **path** \n ```js \n content \n ```
    const markdownRegex = /\*\*(.*?)\*\*\s*```[a-z]*\n([\s\S]*?)```/g;
    while ((match = markdownRegex.exec(text)) !== null) {
      addFile(match[1], match[2]);
    }

    // 2b. Markdown format alternate: `path` \n ```js \n content \n ```
    const markdownAltRegex = /`(.*?)`\s*```[a-z]*\n([\s\S]*?)```/g;
    while ((match = markdownAltRegex.exec(text)) !== null) {
      addFile(match[1], match[2]);
    }

    // 3. Delimiter format: ==== path ==== \n content (until next delimiter or EOF)
    const delimiterRegex = /====\s*(.*?)\s*====\n([\s\S]*?)(?====\s*.*?\s*====|$)/g;
    while ((match = delimiterRegex.exec(text)) !== null) {
      addFile(match[1], match[2].trim());
    }

    // 4. File: path \n ---- \n content \n ----
    const fileDashedRegex = /File:\s*(.*?)\s*\n----\n([\s\S]*?)\n----/g;
    while ((match = fileDashedRegex.exec(text)) !== null) {
      addFile(match[1], match[2]);
    }

    return extractedFiles;
  };

  // Automatically parse text whenever it changes
  useEffect(() => {
    const files = parseText(inputText);
    setParsedFiles(files);
  }, [inputText]);

  const handleDownloadZip = async () => {
    if (parsedFiles.length === 0) {
      alert("No valid files detected in the input text.");
      return;
    }

    setLoading(true);

    try {
      const response = await axios.post(
        'http://localhost:5001/create-zip',
        {
          files: parsedFiles,
        },
        {
          responseType: 'blob',
        }
      );

      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');

      link.href = url;
      link.setAttribute('download', 'project.zip');

      document.body.appendChild(link);
      link.click();

      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      setLoading(false);
    } catch (error) {
      console.error('Error downloading the zip file:', error);
      alert('Error downloading zip file.');
      setLoading(false);
    }
  };

  // Group files by top-level directory for nicer UI
  const fileTree = useMemo(() => {
    const tree = {};
    parsedFiles.forEach(file => {
      const parts = file.path.split('/');
      const root = parts.length > 1 ? parts[0] : '/ (Root)';
      if (!tree[root]) tree[root] = [];
      tree[root].push(file.path);
    });
    return tree;
  }, [parsedFiles]);

  return (
    <div className="max-w-6xl mx-auto p-6 bg-gray-50 min-h-screen flex flex-col md:flex-row gap-6">

      {/* LEFT COLUMN: Input */}
      <div className="flex-1 bg-white rounded-lg shadow-md p-6 flex flex-col">
        <h1 className="text-2xl font-bold mb-2 text-gray-800">
          Smart Project Scaffolder
        </h1>
        <p className="text-gray-600 mb-4 text-sm">
          Paste your code containing file paths and contents (supports Python dictionaries, Markdown, etc.) and it will be magically parsed.
        </p>

        <textarea
          value={inputText}
          onChange={(e) => setInputText(e.target.value)}
          className="w-full flex-1 min-h-[500px] p-4 border border-gray-300 rounded focus:ring-blue-500 focus:border-blue-500 outline-none font-mono text-sm bg-gray-50 resize-none"
          placeholder={`Example:

==== src/App.js ====
console.log("Hello");

==== public/index.html ====
<html>...</html>`}
        />
      </div>

      {/* RIGHT COLUMN: Preview & Download */}
      <div className="w-full md:w-1/3 bg-white rounded-lg shadow-md p-6 flex flex-col">
        <h2 className="text-xl font-bold text-gray-800 mb-4 flex items-center justify-between">
          Parsed Files
          <span className="bg-blue-100 text-blue-800 text-xs px-2 py-1 rounded-full">
            {parsedFiles.length} detected
          </span>
        </h2>

        <div className="flex-1 overflow-y-auto mb-6 bg-gray-50 border border-gray-200 rounded p-4">
          {parsedFiles.length === 0 ? (
            <div className="text-gray-400 text-center mt-10">
              <svg className="w-12 h-12 mx-auto mb-2 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 13h6m-3-3v6m5 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
              No files detected yet. Paste something on the left!
            </div>
          ) : (
            <div className="space-y-4">
              {Object.keys(fileTree).sort().map(folder => (
                <div key={folder}>
                  <h3 className="font-semibold text-gray-700 text-sm mb-1 uppercase tracking-wider">{folder}</h3>
                  <ul className="space-y-1 pl-2">
                    {fileTree[folder].map(path => (
                      <li key={path} className="text-sm text-gray-600 truncate flex items-center">
                        <svg className="w-4 h-4 mr-2 text-gray-400 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z"></path></svg>
                        <span title={path}>{path.substring(path.indexOf('/') + 1) || path}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          )}
        </div>

        <button
          onClick={handleDownloadZip}
          disabled={loading || parsedFiles.length === 0}
          className={`w-full py-3 rounded font-bold text-white transition-colors shadow-sm ${
            loading || parsedFiles.length === 0 ? 'bg-gray-400 cursor-not-allowed' : 'bg-green-600 hover:bg-green-700 shadow-green-500/30 shadow-lg'
          }`}
        >
          {loading ? (
            <span className="flex items-center justify-center">
              <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
              Generating ZIP...
            </span>
          ) : 'Download Project ZIP'}
        </button>
      </div>
    </div>
  );
};

export default App;
